const fn expected_fibonacci_table() -> [u64; 94] {
    let mut table = [0_u64; 94];
    table[1] = 1;
    let mut index = 2_usize;
    while index < table.len() {
        table[index] = table[index - 1] + table[index - 2];
        index += 1;
    }
    table
}

static FOIL_ASYNC_LOSER_ADMITTED: AtomicU64 = AtomicU64::new(0);
static FOIL_ASYNC_LOSER_DROPPED: AtomicU64 = AtomicU64::new(0);
static FOIL_ASYNC_LOSER_COMPLETED: AtomicU64 = AtomicU64::new(0);

#[derive(Serialize, Deserialize, Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct FoilAsyncLoserQueueTelemetry {
    pub admitted_tasks: u64,
    pub dropped_tasks: u64,
    pub completed_tasks: u64,
    pub pending_tasks: u64,
    pub worker_count: usize,
}

pub const FOIL_ASYNC_LOSER_QUEUE_TELEMETRY_THEOREM_IDS: [&str; 8] = [
    FOIL_INTEGRATION_TELEMETRY_BOUNDED_THEOREM_ID,
    FOIL_INTEGRATION_TELEMETRY_ACCOUNTING_THEOREM_ID,
    FOIL_INTEGRATION_TELEMETRY_WINNER_THEOREM_ID,
    FOIL_RUNTIME_ATTESTATION_TRANSPORT_THEOREM_IDS_THEOREM_ID,
    FOIL_RUNTIME_ATTESTATION_TRANSPORT_SUMMARY_THEOREM_ID,
    FOIL_RUNTIME_ATTESTATION_TRANSPORT_ENTROPY_THEOREM_ID,
    FOIL_ENTROPY_CACHE_FRESHNESS_THEOREM_ID,
    FOIL_EQUAL_ENTROPY_CACHE_REUSE_THEOREM_ID,
];

pub fn foil_async_loser_queue_telemetry_theorem_ids() -> &'static [&'static str] {
    &FOIL_ASYNC_LOSER_QUEUE_TELEMETRY_THEOREM_IDS
}

pub fn foil_async_loser_queue_telemetry() -> FoilAsyncLoserQueueTelemetry {
    let admitted_tasks = FOIL_ASYNC_LOSER_ADMITTED.load(Ordering::Relaxed);
    let completed_tasks = FOIL_ASYNC_LOSER_COMPLETED.load(Ordering::Relaxed);
    FoilAsyncLoserQueueTelemetry {
        admitted_tasks,
        dropped_tasks: FOIL_ASYNC_LOSER_DROPPED.load(Ordering::Relaxed),
        completed_tasks,
        pending_tasks: admitted_tasks.saturating_sub(completed_tasks),
        worker_count: foil_async_loser_worker_count(),
    }
}

pub fn foil_async_loser_worker_count() -> usize {
    static WORKER_COUNT: OnceLock<usize> = OnceLock::new();
    *WORKER_COUNT.get_or_init(|| {
        std::env::var("FOIL_ASYNC_LOSER_WORKERS")
            .ok()
            .and_then(|value| value.parse::<usize>().ok())
            .unwrap_or(1)
            .clamp(1, 8)
    })
}

pub fn foil_wait_for_async_loser_queue_drain(timeout: Duration) -> FoilAsyncLoserQueueTelemetry {
    let started = Instant::now();
    loop {
        let telemetry = foil_async_loser_queue_telemetry();
        if telemetry.pending_tasks == 0 || started.elapsed() >= timeout {
            return telemetry;
        }
        thread::sleep(Duration::from_millis(1));
    }
}

#[derive(Clone)]
struct AsyncFoilLoserTask {
    n: u32,
    repetitions: u32,
    observation: AsyncFoilLoserObservation,
}

#[derive(Clone, Copy)]
struct AsyncFoilLoserObservation {
    selected_channels: u16,
    race_candidate_count: u16,
    bisided_score: u16,
    computable: bool,
}

impl From<&RfPhysicsCpuObservation> for AsyncFoilLoserObservation {
    fn from(observation: &RfPhysicsCpuObservation) -> Self {
        Self {
            selected_channels: observation.projection.selected_channels,
            race_candidate_count: observation.projection.race_candidate_count,
            bisided_score: observation
                .frame
                .map(|frame| frame.buley_bisided_score())
                .unwrap_or(BULEY_BISIDED_RHYTHM_GRAIN),
            computable: observation.is_computable(),
        }
    }
}

