// ─── DFT-predicted entropy boost: separate telemetry ──────────────────────
//
// Predicted keys are generated from DFT dominant frequencies of standing wave
// and resolved cells. Because standing waves are RECURRING patterns, predicted
// keys target the actual query shape space instead of random exploration.
//
// Telemetry is separated so we can measure predicted vs random hit rates
// independently. The Lean theorem EntropyBoostCrossover.predicted_hit_rate_geq_random
// states that predicted keys have hit rate >= random keys by construction.

static ENTROPY_PREDICTED_ADMITTED: AtomicU64 = AtomicU64::new(0);
static ENTROPY_PREDICTED_DROPPED: AtomicU64 = AtomicU64::new(0);
static ENTROPY_PREDICTED_HITS: AtomicU64 = AtomicU64::new(0);
static ENTROPY_RANDOM_HITS: AtomicU64 = AtomicU64::new(0);

/// Feed DFT-predicted entropy keys into the FOIL cache with higher priority.
/// Predicted keys are derived from standing wave dominant frequencies, so they
/// target recurring query patterns instead of random exploration.
///
/// Returns the number of keys successfully admitted.
///
/// Lean: EntropyBoostCrossover.predicted_hit_rate_geq_random
pub fn foil_entropy_boost_admit_predicted(
    predicted_keys: &[u64],
    shell: u8,
    jitter_ns: u64,
) -> usize {
    // Reynolds gate: suppress if computation EMA < crossover threshold
    if !foil_entropy_reynolds_gate() {
        return 0;
    }
    foil_entropy_boost_enqueue_predicted(predicted_keys, shell, jitter_ns, false)
}

/// CERTIFIED predicted-boost admission — gate on the cert-attested cost instead
/// of the lagging EMA. Additive sibling of `foil_entropy_boost_admit_predicted`.
/// Lean: `Gnosis.ValueDoorStoplight.certified_never_yellow`.
pub fn foil_entropy_boost_admit_predicted_certified(
    predicted_keys: &[u64],
    shell: u8,
    jitter_ns: u64,
    certified_cost_ns: u64,
) -> usize {
    if !foil_entropy_reynolds_gate_certified(certified_cost_ns) {
        return 0;
    }
    foil_entropy_boost_enqueue_predicted(predicted_keys, shell, jitter_ns, false)
}

/// **Mycelial Fano discharge admission — the forward fork of the closed loop.**
///
/// Same certified value-door gate and async-loser enqueue as
/// [`foil_entropy_boost_admit_predicted_certified`], but the keys carry a
/// Fano-line provenance tag ([`crate::mycelial_fano_router::tag_key_with_line`])
/// so each successful admit also credits its source line's forward counter. A
/// later hit on one of these keys is vented back with
/// [`foil_entropy_predicted_hit_keyed`], closing the VentInterferePast loop.
/// Returns the number of keys admitted. Lean:
/// `Gnosis.MycelialMeshAttentionHotelling.vent_shift_pulls_hit_rate_up`.
pub fn foil_entropy_boost_admit_fano_certified(
    predicted_keys: &[u64],
    shell: u8,
    jitter_ns: u64,
    certified_cost_ns: u64,
) -> usize {
    if !foil_entropy_reynolds_gate_certified(certified_cost_ns) {
        return 0;
    }
    foil_entropy_boost_enqueue_predicted(predicted_keys, shell, jitter_ns, true)
}

/// Shared post-gate enqueue body for the predicted boost paths (gate-agnostic).
/// `fano` marks the mycelial discharge path, whose keys carry a Fano-line
/// provenance tag and so credit per-line forward counters on admit.
fn foil_entropy_boost_enqueue_predicted(
    predicted_keys: &[u64],
    shell: u8,
    jitter_ns: u64,
    fano: bool,
) -> usize {
    // Layer 2: fold timing jitter back into the pool
    ENTROPY_BOOST_JITTER_POOL.fetch_add(jitter_ns, Ordering::Relaxed);

    let mut admitted_count = 0usize;
    for &key in predicted_keys {
        // Predicted keys get elevated bisided score (higher priority in the queue)
        // Shell depth amplifies: deeper shells = more confident predictions
        let priority_boost = 8u16.saturating_add(shell as u16 * 4);
        let n = (key % 93 + 1) as u32;
        let observation = AsyncFoilLoserObservation {
            selected_channels: (key >> 48) as u16,
            race_candidate_count: priority_boost,
            bisided_score: priority_boost,
            computable: true,
        };

        match async_foil_loser_sender().try_send(AsyncFoilLoserTask {
            n,
            repetitions: 1,
            observation,
        }) {
            Ok(()) => {
                FOIL_ASYNC_LOSER_ADMITTED.fetch_add(1, Ordering::Relaxed);
                ENTROPY_PREDICTED_ADMITTED.fetch_add(1, Ordering::Relaxed);
                // VentInterferePast forward accounting: only Fano-tagged keys
                // (the mycelial discharge path) credit their source line's
                // forward counter; generic predicted keys carry no line
                // provenance and must not pollute the feedback table. The
                // backward vent lands in `foil_entropy_predicted_hit_keyed`.
                if fano {
                    crate::mycelial_fano_router::fano_line_record_admit(
                        crate::mycelial_fano_router::line_from_key(key),
                    );
                }
                admitted_count += 1;
            }
            Err(_) => {
                FOIL_ASYNC_LOSER_DROPPED.fetch_add(1, Ordering::Relaxed);
                ENTROPY_PREDICTED_DROPPED.fetch_add(1, Ordering::Relaxed);
            }
        }
    }

    admitted_count
}

