// ─── Layer 1b: Standing Wave Audio Entropy Boost ─────────────────────────
//
// Bridges DFT peaks from standing wave audio analysis into the FOIL entropy
// pool. Each (bin, magnitude) pair is hashed through the golden-ratio
// Fibonacci multiplier to produce predicted cache keys targeting recurring
// spectral patterns. Admitted through the predicted-entropy path at shell=2.

/// Feed standing wave audio DFT peaks into the FOIL entropy pool.
///
/// `dft_peaks`: slice of (frequency_bin, magnitude) pairs from audio DFT.
/// `jitter_ns`: timing jitter from the audio capture path.
///
/// Returns the number of keys successfully admitted.
///
/// Lean: EntropyBoostCrossover.predicted_hit_rate_geq_random
#[cfg(feature = "spectrum-waterfall")]
pub fn foil_entropy_boost_standing_wave(dft_peaks: &[(u16, f32)], jitter_ns: u64) -> usize {
    if !foil_entropy_boost_enabled() {
        return 0;
    }
    let predicted_keys: Vec<u64> = dft_peaks
        .iter()
        .map(|&(bin, mag)| {
            let raw = (bin as u64) << 32 | (mag.to_bits() as u64);
            raw.wrapping_mul(11_400_714_819_323_198_485) // 2^64 / phi
        })
        .collect();
    let admitted = foil_entropy_boost_admit_predicted(&predicted_keys, 2, jitter_ns);
    STANDING_WAVE_ENTROPY_ADMITTED.fetch_add(admitted as u64, Ordering::Relaxed);
    let dropped = predicted_keys.len().saturating_sub(admitted);
    STANDING_WAVE_ENTROPY_DROPPED.fetch_add(dropped as u64, Ordering::Relaxed);
    admitted
}

/// Telemetry for standing wave audio entropy admission.
/// Returns (admitted, dropped).
pub fn foil_standing_wave_entropy_telemetry() -> (u64, u64) {
    (
        STANDING_WAVE_ENTROPY_ADMITTED.load(Ordering::Relaxed),
        STANDING_WAVE_ENTROPY_DROPPED.load(Ordering::Relaxed),
    )
}

fn async_foil_loser_sender() -> &'static SyncSender<AsyncFoilLoserTask> {
    static SENDER: OnceLock<SyncSender<AsyncFoilLoserTask>> = OnceLock::new();
    SENDER.get_or_init(|| {
        let (sender, receiver) = sync_channel::<AsyncFoilLoserTask>(FOIL_ASYNC_LOSER_QUEUE_DEPTH);
        let receiver = Arc::new(Mutex::new(receiver));
        for worker_index in 0..foil_async_loser_worker_count() {
            let receiver = Arc::clone(&receiver);
            let _ = thread::Builder::new()
                .name(format!("foil-async-loser-cache-{worker_index}"))
                .spawn(move || loop {
                    let task = match receiver.lock() {
                        Ok(receiver) => receiver.recv(),
                        Err(_) => break,
                    };
                    let Ok(task) = task else {
                        break;
                    };
                    let _ = fibonacci_fast_kernel_measurement(task.n, task.repetitions);
                    for _ in 0..task.repetitions {
                        let _ = std::hint::black_box(rf_fibonacci_async_loser_value(
                            task.n,
                            task.observation,
                        ));
                    }
                    FOIL_ASYNC_LOSER_COMPLETED.fetch_add(1, Ordering::Relaxed);
                });
        }
        sender
    })
}

fn enqueue_async_foil_loser_work(
    n: u32,
    repetitions: u32,
    observation: &RfPhysicsCpuObservation,
) -> bool {
    match async_foil_loser_sender().try_send(AsyncFoilLoserTask {
        n,
        repetitions,
        observation: AsyncFoilLoserObservation::from(observation),
    }) {
        Ok(()) => {
            FOIL_ASYNC_LOSER_ADMITTED.fetch_add(1, Ordering::Relaxed);
            true
        }
        Err(TrySendError::Full(_)) | Err(TrySendError::Disconnected(_)) => {
            FOIL_ASYNC_LOSER_DROPPED.fetch_add(1, Ordering::Relaxed);
            false
        }
    }
}

