pub struct GnosisFoilJsonlRawIngressEngine<R> {
    reader: R,
    descriptor: GnosisFoilRawIngressDescriptor,
}

impl<R: BufRead> GnosisFoilJsonlRawIngressEngine<R> {
    pub fn new(reader: R, descriptor: GnosisFoilRawIngressDescriptor) -> Self {
        Self { reader, descriptor }
    }

    fn read_capture_line(&mut self) -> Result<String, String> {
        let mut line = String::new();
        loop {
            line.clear();
            let bytes_read = self
                .reader
                .read_line(&mut line)
                .map_err(|error| format!("raw ingress JSONL read failed: {error}"))?;
            if bytes_read == 0 {
                return Err("raw ingress JSONL ended before a capture object".to_string());
            }
            if !line.trim().is_empty() {
                return Ok(line.trim().to_string());
            }
        }
    }
}

impl<R: BufRead> GnosisFoilRawIngressEngine for GnosisFoilJsonlRawIngressEngine<R> {
    fn descriptor(&self) -> GnosisFoilRawIngressDescriptor {
        self.descriptor.clone()
    }

    fn capture_block(&mut self) -> Result<GnosisFoilRawCapture, String> {
        let line = self.read_capture_line()?;
        let capture: GnosisFoilRawCapture = serde_json::from_str(&line)
            .map_err(|error| format!("raw ingress JSONL capture did not parse: {error}"))?;
        if capture.descriptor != self.descriptor {
            return Err(
                "raw ingress JSONL descriptor does not match engine descriptor".to_string(),
            );
        }
        if capture.bytes.len() > capture.descriptor.block_size_bytes {
            return Err("raw ingress JSONL capture exceeds descriptor block size".to_string());
        }
        Ok(capture)
    }
}

