#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct RfFibonacciSmartSkipCache {
    pub shape_key: String,
    pub target_n: u32,
    pub value: u64,
    pub rf_frame_width: u16,
    pub rf_candidate_count: u16,
    pub bisided_score: u16,
    pub retention_floor: u64,
    pub retained_witnesses: Vec<RfAdditionTrace>,
    pub recomputable_steps: Vec<u32>,
    /// Number of times this cache entry was successfully used as a hit.
    /// Incremented on every cache-hit path. Combined with `retained_witnesses.len()`
    /// to compute liquid density: `density = retained_witnesses.len() × (hit_count + 1)`.
    pub hit_count: u32,
    /// Accumulated density of witnesses evicted from the retained set
    /// (`cache_priority × 1` per evicted witness). Landauer heat accounting.
    pub heat_released: u64,
}

impl RfFibonacciSmartSkipCache {
    /// Memory pressure as a percentage [0, 100].
    ///
    /// Computed as `(retained_witnesses.len() * 100) / target_n`. At 100 every
    /// step is retained; lower values indicate the retention floor has pruned
    /// some witnesses. Callers can use this to decide whether to tighten the
    /// floor on the next cache build.
    pub fn memory_pressure(&self) -> u64 {
        if self.target_n == 0 {
            return 0;
        }
        (self.retained_witnesses.len() as u64 * 100) / self.target_n as u64
    }
}

