pub fn foil_bracket_inside_machine_cell(
    bracket: &FoilScaledBracket,
    cell: &FoilMachineCell,
    lower_midpoint_twice: u128,
    upper_midpoint_twice: u128,
) -> bool {
    lower_midpoint_twice.saturating_mul(bracket.lower.denominator)
        < 2_u128
            .saturating_mul(cell.denominator)
            .saturating_mul(bracket.lower.numerator)
        && 2_u128
            .saturating_mul(cell.denominator)
            .saturating_mul(bracket.upper.numerator)
            < upper_midpoint_twice.saturating_mul(bracket.upper.denominator)
}

pub fn foil_scaled_ratio_le(left: &FoilScaledRatio, right: &FoilScaledRatio) -> bool {
    left.numerator.saturating_mul(right.denominator)
        <= right.numerator.saturating_mul(left.denominator)
}

pub fn foil_scaled_ratio_eq(left: &FoilScaledRatio, right: &FoilScaledRatio) -> bool {
    left.numerator.saturating_mul(right.denominator)
        == right.numerator.saturating_mul(left.denominator)
}

pub fn foil_bracket_refines(previous: &FoilScaledBracket, next: &FoilScaledBracket) -> bool {
    foil_scaled_ratio_le(&previous.lower, &next.lower)
        && foil_scaled_ratio_le(&next.upper, &previous.upper)
}

pub fn foil_bracket_non_discrete(bracket: &FoilScaledBracket) -> bool {
    !foil_scaled_ratio_eq(&bracket.lower, &bracket.upper)
}

#[inline(always)]
pub fn foil_admit_monster_aeon_fano_fast_path(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> FoilMonsterAeonFanoFastPath {
    foil_admit_monster_aeon_fano_fast_path_with_policy(
        MonsterFanoXorPayloadDispatchPolicy::RandomValidated,
        None,
        lhs_column,
        rhs_column,
        residual_validated,
        fingerprint_verified,
    )
}

#[inline(always)]
pub fn foil_admit_monster_aeon_fano_fast_path_with_policy(
    policy: MonsterFanoXorPayloadDispatchPolicy,
    cache: Option<&mut FanoMycelialRouteCache>,
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> FoilMonsterAeonFanoFastPath {
    let theorem_ids = vec![FOIL_MONSTER_AEON_FANO_FAST_PATH_THEOREM_ID];
    let route = route_monster_fano_xor_payload_packed_with_policy(
        policy,
        cache,
        lhs_column,
        rhs_column,
        residual_validated,
        fingerprint_verified,
    );
    match fano_xor_payload_route_status(route) {
        FANO_XOR_ROUTE_ADMITTED => {
            let payload = fano_xor_payload_route_value(route);
            let aeon_gate = fano_xor_payload_route_gate(route);
            let lhs_phase = monster_column_phase(lhs_column);
            let rhs_phase = monster_column_phase(rhs_column);
            FoilMonsterAeonFanoFastPath {
                admitted: true,
                reason: "certified-fano-xor",
                monster_columns: [lhs_column, rhs_column],
                packed_route: route,
                aeon_phases: Some([lhs_phase, rhs_phase]),
                aeon_gate: Some(aeon_gate),
                fano_states: Some([lhs_phase + 1, rhs_phase + 1]),
                xor_payload: Some(payload),
                completion: Some(payload),
                orientation_sign: Some(if lhs_phase < rhs_phase { 1 } else { -1 }),
                positive_gate: Some(true),
                residual_validated,
                fingerprint_verified,
                theorem_ids,
            }
        }
        FANO_XOR_ROUTE_SAME_PHASE => {
            let phase = fano_xor_payload_route_value(route);
            FoilMonsterAeonFanoFastPath {
                admitted: false,
                reason: "same-aeon-phase",
                monster_columns: [lhs_column, rhs_column],
                packed_route: route,
                aeon_phases: Some([phase, phase]),
                aeon_gate: None,
                fano_states: None,
                xor_payload: None,
                completion: None,
                orientation_sign: None,
                positive_gate: None,
                residual_validated,
                fingerprint_verified,
                theorem_ids,
            }
        }
        FANO_XOR_ROUTE_OUTSIDE_SUBATLAS => {
            let aeon_gate = fano_xor_payload_route_gate(route);
            FoilMonsterAeonFanoFastPath {
                admitted: false,
                reason: "outside-fano-subatlas",
                monster_columns: [lhs_column, rhs_column],
                packed_route: route,
                aeon_phases: None,
                aeon_gate: Some(aeon_gate),
                fano_states: None,
                xor_payload: None,
                completion: None,
                orientation_sign: None,
                positive_gate: None,
                residual_validated,
                fingerprint_verified,
                theorem_ids,
            }
        }
        FANO_XOR_ROUTE_SHADOW_REQUIRED => {
            let aeon_gate = fano_xor_payload_route_gate(route);
            FoilMonsterAeonFanoFastPath {
                admitted: false,
                reason: "shadow-validation-required",
                monster_columns: [lhs_column, rhs_column],
                packed_route: route,
                aeon_phases: None,
                aeon_gate: Some(aeon_gate),
                fano_states: None,
                xor_payload: None,
                completion: None,
                orientation_sign: None,
                positive_gate: None,
                residual_validated,
                fingerprint_verified,
                theorem_ids,
            }
        }
        _ => unreachable!("route status is packed into two bits"),
    }
}

pub fn benchmark_foil_monster_aeon_fano_fast_path(
    iterations: u64,
) -> FoilMonsterAeonFanoFastPathBenchReport {
    let iterations = iterations.max(1);
    let mut states = 0xC2B2_AE35_79B9_7F4Au64;
    let mut admitted = 0u64;
    let mut same_phase = 0u64;
    let mut outside_fano_subatlas = 0u64;
    let mut shadow_validation_required = 0u64;
    let mut checksum = 0u64;

    let started = Instant::now();
    for index in 0..iterations {
        states = states
            .wrapping_mul(2862933555777941757)
            .wrapping_add(3037000493);
        let lhs = (states as u32) % crate::fano_runtime::MONSTER_MOONSHINE_DIM;
        let rhs = ((states >> 23) as u32) % crate::fano_runtime::MONSTER_MOONSHINE_DIM;
        let residual_validated = index % 4 != 0;
        let fingerprint_verified = index % 8 != 0;
        let decision = foil_admit_monster_aeon_fano_fast_path(
            lhs,
            rhs,
            residual_validated,
            fingerprint_verified,
        );

        match decision.reason {
            "certified-fano-xor" => admitted += 1,
            "same-aeon-phase" => same_phase += 1,
            "outside-fano-subatlas" => outside_fano_subatlas += 1,
            "shadow-validation-required" => shadow_validation_required += 1,
            _ => {}
        }
        if let Some(gate) = decision.aeon_gate {
            checksum = checksum.wrapping_add(u64::from(gate[0]) + u64::from(gate[1]));
        }
        if let Some(payload) = decision.xor_payload {
            checksum = checksum.wrapping_add(u64::from(payload));
        }
        if let Some(positive_gate) = decision.positive_gate {
            checksum = checksum.wrapping_add(u64::from(positive_gate));
        }
    }

    let elapsed = started.elapsed();
    let seconds = elapsed.as_secs_f64().max(f64::EPSILON);
    FoilMonsterAeonFanoFastPathBenchReport {
        iterations,
        elapsed_ns: elapsed.as_nanos(),
        decisions_per_second: iterations as f64 / seconds,
        admitted,
        same_phase,
        outside_fano_subatlas,
        shadow_validation_required,
        checksum,
    }
}

pub fn foil_god_weight(budget: u128, rejection: u128) -> u128 {
    budget.saturating_sub(rejection.min(budget)) + 1
}

pub fn foil_god_bracket_weight_reusable(
    budget: u128,
    outer: &FoilScaledBracket,
    inner: &FoilScaledBracket,
    outer_rejection: u128,
    inner_rejection: u128,
) -> bool {
    foil_bracket_refines(outer, inner)
        && foil_bracket_non_discrete(inner)
        && inner_rejection <= outer_rejection
        && foil_god_weight(budget, outer_rejection) < foil_god_weight(budget, inner_rejection)
}

pub fn foil_causal_diamond_should_refine(
    outer_time_width: u128,
    inner_time_width: u128,
    sliver_limit: u128,
) -> bool {
    inner_time_width < outer_time_width && inner_time_width > sliver_limit
}

