fn phi_bracket(
    lower_numerator: u128,
    lower_denominator: u128,
    upper_numerator: u128,
    upper_denominator: u128,
) -> FoilScaledBracket {
    FoilScaledBracket {
        lower: FoilScaledRatio {
            numerator: lower_numerator,
            denominator: lower_denominator,
        },
        upper: FoilScaledRatio {
            numerator: upper_numerator,
            denominator: upper_denominator,
        },
    }
}

