    #[test]
    fn rf_gated_fibonacci_matches_reference() {
        let observation = RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
            potential_channels: MONSTER_VECTOR_FLOOR,
            witness_signal: 20,
            activation_threshold: 20,
        });

        let (value, additions) = rf_fibonacci(20, &observation).expect("fib");

        assert_eq!(value, expected_fibonacci(20).expect("reference"));
        assert_eq!(additions.len(), 19);
        assert_eq!(additions[0].load_bearing_depth, 19);
        assert_eq!(additions[18].load_bearing_depth, 1);
        assert_eq!(
            additions[0].cache_priority % u64::from(BULEY_BISIDED_RHYTHM_GRAIN),
            0
        );
        assert!(additions[0].cache_priority > additions[18].cache_priority);
        for window in additions.windows(2) {
            let earlier = &window[0];
            let later = &window[1];
            if later.carry_events <= earlier.carry_events {
                assert!(
                    later.cache_priority <= earlier.cache_priority,
                    "cache priority should descend with step when carry pressure does not rise"
                );
            }
        }
        assert!(additions.iter().all(|trace| {
            trace.rf_frame_width == TEN_BIT_FRAME_WIDTH
                && trace.rf_candidate_count == TEN_BIT_FRAME_WIDTH
        }));

        let retention_plan = rf_plan_witness_retention(&additions, additions[0].cache_priority);
        assert_eq!(retention_plan.len(), additions.len());
        assert_eq!(
            retention_plan[0].action,
            RfWitnessRetentionAction::RetainWitness
        );
        assert_eq!(
            retention_plan[18].action,
            RfWitnessRetentionAction::RecomputeIfNeeded
        );
    }

