    #[test]
    fn rf_fibonacci_packed_shape_key_agrees_with_string_key_equality() {
        // The packed key is the same cache identity as the format! string —
        // equal packed keys iff equal string keys — with no allocation.
        let observations = [
            RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
                potential_channels: MONSTER_VECTOR_FLOOR,
                witness_signal: 20,
                activation_threshold: 20,
            }),
            RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
                potential_channels: MONSTER_VECTOR_FLOOR + 8192,
                witness_signal: 255,
                activation_threshold: 20,
            }),
            RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
                potential_channels: MONSTER_VECTOR_FLOOR,
                witness_signal: 19,
                activation_threshold: 20,
            }),
            RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
                potential_channels: MONSTER_VECTOR_FLOOR,
                witness_signal: 21,
                activation_threshold: 20,
            }),
        ];
        for n in [1u32, 20, 93] {
            for lhs in &observations {
                for rhs in &observations {
                    assert_eq!(
                        rf_fibonacci_packed_shape_key(n, lhs)
                            == rf_fibonacci_packed_shape_key(n, rhs),
                        rf_fibonacci_shape_key(n, lhs) == rf_fibonacci_shape_key(n, rhs),
                        "static packed/string key equality must coincide"
                    );
                    assert_eq!(
                        rf_fibonacci_packed_dynamic_shape_key(n, lhs)
                            == rf_fibonacci_packed_dynamic_shape_key(n, rhs),
                        rf_fibonacci_dynamic_shape_key(n, lhs)
                            == rf_fibonacci_dynamic_shape_key(n, rhs),
                        "dynamic packed/string key equality must coincide"
                    );
                }
            }
            // Distinct n always separates keys.
            assert_ne!(
                rf_fibonacci_packed_shape_key(n, &observations[0]),
                rf_fibonacci_packed_shape_key(n + 1, &observations[0])
            );
        }
    }

